<script setup>
import { onMounted, onUnmounted, ref } from 'vue'
const agents=ref([]),selected=ref(null),error=ref(''),workflow=ref(null),tasks=ref([])
async function load(){try{agents.value=await fetch('/api/agents').then(r=>r.json());const flows=await fetch('/api/workflows').then(r=>r.json());workflow.value=flows.at(-1);if(workflow.value)tasks.value=(await fetch('/api/workflows/'+workflow.value.id).then(r=>r.json())).tasks;selected.value??=agents.value[0]}catch(e){error.value=e.message}}
let timer;onMounted(()=>{load();timer=setInterval(load,2000)});onUnmounted(()=>clearInterval(timer))
</script>
<template><main><header><b>● A2A Agent Office</b><span>当前确认任务 · {{ workflow?.title||'等待任务' }}</span><div class="metrics"><b>{{ tasks.filter(t=>t.status==='passed').length }}/{{ tasks.length }}<small>已完成节点</small></b><b>0<small>上下文消息</small></b><b>{{ workflow?.status?.toUpperCase()||'IDLE' }}<small>工作流状态</small></b></div><button @click="load">刷新</button></header><div class="layout"><section class="office"><small>A2A WORKSPACE · 上下文 agent 到 agent 直接流转</small><svg><line v-for="(_,i) in agents.slice(1)" :key="i" x1="14%" y1="65%" :x2="35+i*20+'%'" :y2="30+i%2*40+'%'" /></svg><article v-for="(agent,i) in agents" :key="agent.key" :class="{active:selected?.key===agent.key}" :style="{left:12+(i%3)*30+'%',top:22+Math.floor(i/3)*40+'%'}" @click="selected=agent"><i>{{ agent.name[0] }}</i><b>{{ agent.name }}</b><span>{{ agent.key }}</span><p>{{ tasks.find(t=>t.agent===agent.key)?.stage||agent.role }} · {{ tasks.find(t=>t.agent===agent.key)?.status||'已注册' }}</p></article><aside v-if="selected"><button @click="selected=null">×</button><h3>{{ selected.name }}</h3><p>Agent ID：{{ selected.key }}</p><p>角色：{{ selected.role }}</p><p>当前节点：{{ tasks.find(t=>t.agent===selected.key)?.stage||'未分配' }}</p><p>状态：{{ tasks.find(t=>t.agent===selected.key)?.status||'已注册' }}</p></aside><p v-if="error" class="error">{{ error }}</p></section><aside class="feed"><b>上下文流转日志</b><p v-for="task in tasks" :key="task.id">{{ task.stage }} → {{ task.agent }} · {{ task.status }}</p></aside></div></main></template>
<style scoped>main{height:100vh;font-family:"Microsoft YaHei",sans-serif;color:#1d2939;background:#f8fbfd}header{height:56px;display:flex;align-items:center;gap:28px;padding:0 24px;background:#fff;border-bottom:1px solid #dbe3ec}header span,.office article span{color:#778394;font-size:12px}.metrics{display:flex;gap:24px;margin-left:auto}.metrics b{text-align:center}.metrics small{display:block;color:#94a0af;font-weight:400;font-size:10px}header button{margin-left:0}.layout{height:calc(100vh - 56px);display:grid;grid-template-columns:1fr 300px}.office{position:relative;overflow:hidden;background-image:radial-gradient(#dce4ec 1px,transparent 1px);background-size:22px 22px}.office>small{position:absolute;top:16px;left:22px;color:#98a4b3}.office svg{position:absolute;width:100%;height:100%}line{stroke:#c9d4df;stroke-dasharray:5 5}.office article{position:absolute;width:190px;padding:14px;border:1px solid #dbe3ec;border-radius:13px;background:#fff;box-shadow:0 3px 10px #26384b18;cursor:pointer}.office article.active{box-shadow:0 0 0 2px #4386ee,0 12px 25px #26384b22}.office i{display:inline-grid;place-items:center;width:34px;height:34px;margin-right:9px;border-radius:50%;background:#4386ee;color:#fff;font-style:normal}.office article span{display:block;margin:5px 0}.office article p,.office aside p{margin:8px 0 0;color:#667385;font-size:12px}.office aside{position:absolute;z-index:2;width:280px;padding:16px;right:30px;bottom:30px;border:1px solid #dbe3ec;border-radius:13px;background:#fff;box-shadow:0 14px 36px #24364c24}.office aside button{float:right;border:0;background:none;font-size:20px}.feed{padding:18px;border-left:1px solid #dbe3ec;background:#fff}.feed p{margin-top:40px;color:#98a4b3;font-size:13px}.error{position:absolute;left:20px;bottom:20px;color:#d44}</style>
